  2371 |     Pred = ICmpInst::getInversePredicate(Pred);
  2372 |   // ctpop(V) u< 2
  2373 |   if (OrZero && Pred == ICmpInst::ICMP_ULT && *RHSC == 2)
  2374 |     return true;
  2375 |   // ctpop(V) == 1
  2376 |   return Pred == ICmpInst::ICMP_EQ && *RHSC == 1;
  2377 | }
