  2400 |       if (isImpliedToBeAPowerOfTwoFromCond(V, OrZero, I->getArgOperand(0),
  2401 |                                            /*CondIsTrue=*/true) &&
  2402 |           isValidAssumeForContext(I, Q.CxtI, Q.DT))
  2403 |         return true;
  2404 |     }
  2405 |   }
