/// Return true if the dominating conditions tell us that V1 != V2.
static bool isNonEqualByDominatingCondition(const Value *V1, const Value *V2,
                                            const APInt &DemandedElts,
                                            unsigned Depth,
                                            const SimplifyQuery &Q) {
  // We need a context and dominating conditions.
  if (!Q.CxtI || !Q.DC || !Q.DT)
    return false;

  // Pick either V1 or V2 to look up in the Dominating Condition Cache.
  // If V1 is used in a comparison with V2 in a dominating branch condition,
  // then we might learn something.
  const auto CheckDominatingCondition = [&](const Value *V,
                                            const Value *Other) {
    for (BranchInst *BI : Q.DC->conditionsFor(V)) {
      Value *Cond = BI->getCondition();
      // Look for icmp ne V, Other or icmp eq V, Other.
      CmpPredicate Pred;
      const Value *LHS, *RHS;
      if (!match(Cond, m_ICmp(Pred, m_Value(LHS), m_Value(RHS))))
        continue;

      // Check if this compares V with Other.
      if ((LHS != V || RHS != Other) && (LHS != Other || RHS != V))
        continue;

      // If the condition is ICMP_NE and dominates the false successor,
      // then V != Other on that path.
      // If the condition is ICMP_EQ and dominates the true successor,
      // then V != Other on the false successor.
      BasicBlockEdge FalseEdge(BI->getParent(), BI->getSuccessor(1));
      BasicBlockEdge TrueEdge(BI->getParent(), BI->getSuccessor(0));

      if (Pred == ICmpInst::ICMP_NE &&
          Q.DT->dominates(FalseEdge, Q.CxtI->getParent())) {
        return true;
      }
      if (Pred == ICmpInst::ICMP_EQ &&
          Q.DT->dominates(TrueEdge, Q.CxtI->getParent())) {
        return true;
      }
    }
    return false;
  };

  return CheckDominatingCondition(V1, V2) || CheckDominatingCondition(V2, V1);
}

